import requests

def ollama_ready(base_url="http://localhost:11434") -> bool:
    """Health check — call at agent startup before any model call."""
    try:
        return requests.get(f"{base_url}/api/tags", timeout=2).status_code == 200
    except Exception:
        return False

def check_and_generate(prompt: str, model="llama3.1:8b") -> str:
    OLLAMA = "http://localhost:11434"
    if not ollama_ready(OLLAMA):
        raise RuntimeError("Ollama not running. Start with: ollama serve")
    models = [m["name"] for m in
              requests.get(f"{OLLAMA}/api/tags").json()["models"]]
    if model not in models:
        raise RuntimeError(f"Model {model!r} not pulled. Run: ollama pull {model}")
    r = requests.post(f"{OLLAMA}/api/generate",
                      json={"model": model, "prompt": prompt, "stream": False},
                      timeout=120)
    return r.json()["response"]

from openai import OpenAI

# Local Ollama — identical API surface as cloud
local_client = OpenAI(base_url="http://localhost:11434/v1", api_key="ollama")

# Cloud — only base_url and api_key change
cloud_client = OpenAI()  # uses OPENAI_API_KEY from env

def get_client(use_local: bool = False):
    if use_local:
        return OpenAI(base_url="http://localhost:11434/v1", api_key="ollama")
    return OpenAI()
